const email = $input.first().json;

const threadId = email.threadId || email.id;
const sender = email.From || email.from || '';
const subject = email.Subject || email.subject || '';

// Extract plain text body
let body = '';
if (email.text) {
  body = email.text;
} else if (email.snippet) {
  body = email.snippet;
} else if (email.payload && email.payload.body && email.payload.body.data) {
  body = Buffer.from(email.payload.body.data, 'base64').toString('utf-8');
}

// Clean up quoted reply chains
body = body.replace(/On .* wrote:[\s\S]*/i, '').trim();
body = body.replace(/_{3,}[\s\S]*/g, '').trim();

return [{
  json: {
    threadId,
    sender,
    subject,
    body,
    messageId: email.id,
    timestamp: new Date().toISOString()
  }
}];
